const STATE_KEY = "gaokao_yuwen_selftest_v1";
const CATEGORY_LABELS = {
  all: "全部题库",
  basic: "基础与语感",
  language: "语言文字运用",
  modern1: "现代文阅读Ⅰ",
  modern2: "现代文阅读Ⅱ",
  classical: "古代诗文阅读Ⅰ",
  poetry: "古代诗文阅读Ⅱ"
};
const VIEW_LABELS = {
  dashboard: "总览",
  knowledge: "方法库",
  practice: "分题自测",
  paper: "整卷模式",
  writing: "写作强化",
  review: "复盘中心"
};
const KNOWLEDGE_TO_BANK = {
  language: "language",
  modern1: "modern1",
  modern2: "modern2",
  classical: "classical",
  poetry: "poetry"
};
const PRACTICE_CATEGORY_ORDER = ["all","basic","language","modern1","modern2","classical","poetry"];
const ALL_QUESTIONS = [];
const QUESTION_LOOKUP = {};
Object.entries(DATA.banks).forEach(([bankKey, bank]) => {
  bank.items.forEach((item, idx) => {
    const q = Object.assign({}, item, { bankKey, bankTitle: bank.title, orderInBank: idx + 1 });
    ALL_QUESTIONS.push(q);
    QUESTION_LOOKUP[q.id] = q;
  });
});
const WRITING_LOOKUP = Object.fromEntries(DATA.writingPrompts.map(p => [p.id, p]));
const PAPER_LOOKUP = Object.fromEntries(DATA.paperPresets.map(p => [p.id, p]));


function defaultState(){
  return {
    activeView: "dashboard",
    knowledgeMain: "modern1",
    knowledgeQuery: "",
    practiceCategory: "modern1",
    practiceSource: "all",
    practiceType: "all",
    practiceWrongFirst: false,
    practiceQuestionId: "",
    practiceQuery: "",
    practiceDifficulty: "all",
    practiceStatus: "all",
    practiceOnlyFav: false,
    focusMode: false,
    reviewCategory: "all",
    reviewTag: "",
    records: {},
    rules: [],
    notes: [],
    history: [],
    writingId: DATA.writingPrompts[0].id,
    writingDrafts: {},
    paperPreset: DATA.paperPresets[0].id,
    paperSessions: {}
  };
}


function hydrateState(raw){
  const base = defaultState();
  if(!raw || typeof raw !== "object") return base;
  return {
    ...base,
    ...raw,
    records: raw.records && typeof raw.records === "object" ? raw.records : {},
    rules: Array.isArray(raw.rules) ? raw.rules : [],
    notes: Array.isArray(raw.notes) ? raw.notes : [],
    history: Array.isArray(raw.history) ? raw.history : [],
    writingDrafts: raw.writingDrafts && typeof raw.writingDrafts === "object" ? raw.writingDrafts : {},
    paperSessions: raw.paperSessions && typeof raw.paperSessions === "object" ? raw.paperSessions : {}
  };
}

function loadState(){
  try{
    const raw = localStorage.getItem(STATE_KEY);
    if(!raw) return defaultState();
    return hydrateState(JSON.parse(raw));
  }catch(err){
    return defaultState();
  }
}

let state = loadState();

let timerHandle = null;
const DEVICE_KEY = "gaokao_yuwen_device_profile_v2";
const DEVICE_LABELS = { desktop: "桌面端", mobile: "手机端" };

function getDeviceProfile(){
  return localStorage.getItem(DEVICE_KEY) || "";
}

function detectDeviceProfile(){
  return window.innerWidth <= 860 ? "mobile" : "desktop";
}

function applyDeviceProfile(profile, persist = true){
  const target = profile === "mobile" ? "mobile" : "desktop";
  document.body.classList.remove("device-mobile", "device-desktop");
  document.body.classList.add(`device-${target}`);
  const badge = document.getElementById("deviceBadge");
  if(badge) badge.textContent = `设备：${DEVICE_LABELS[target]}`;
  const gate = document.getElementById("deviceGate");
  if(gate) gate.classList.remove("show");
  if(persist) localStorage.setItem(DEVICE_KEY, target);
}

function openDeviceGate(force = false){
  const gate = document.getElementById("deviceGate");
  if(!gate) return;
  if(force || !getDeviceProfile()) gate.classList.add("show");
}

function selectDeviceProfile(profile){
  applyDeviceProfile(profile, true);
  showToast(`已切换到${DEVICE_LABELS[profile === "mobile" ? "mobile" : "desktop"]}`);
}

function initDeviceProfile(){
  const saved = getDeviceProfile();
  applyDeviceProfile(saved || detectDeviceProfile(), !!saved);
  if(!saved) openDeviceGate();
}

function toggleFocusMode(){
  state.focusMode = !state.focusMode;
  saveState();
  renderApp();
  showToast(state.focusMode ? "已开启专注模式" : "已关闭专注模式");
}

function countChars(value){
  return String(value || "").replace(/\s/g, "").length;
}

function safeClipboardCopy(text){
  if(navigator.clipboard && typeof navigator.clipboard.writeText === "function"){
    return navigator.clipboard.writeText(text).catch(() => {
      const ta = document.createElement("textarea");
      ta.value = text;
      document.body.appendChild(ta);
      ta.select();
      document.execCommand("copy");
      ta.remove();
    });
  }
  return new Promise(resolve => {
    const ta = document.createElement("textarea");
    ta.value = text;
    document.body.appendChild(ta);
    ta.select();
    document.execCommand("copy");
    ta.remove();
    resolve();
  });
}

function ensureHistoryArray(){
  if(!Array.isArray(state.history)) state.history = [];
  return state.history;
}

function pushHistory(entry){
  const arr = ensureHistoryArray();
  arr.push({ id: uid(), ts: Date.now(), ...entry });
  if(arr.length > 400) state.history = arr.slice(-400);
  saveState();
}

function dayKey(ts){
  const d = new Date(ts);
  return `${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,"0")}-${String(d.getDate()).padStart(2,"0")}`;
}

function dailyTrend(days = 7){
  const now = new Date();
  const arr = [];
  const map = {};
  for(let i = days - 1; i >= 0; i--){
    const d = new Date(now);
    d.setDate(d.getDate() - i);
    const key = dayKey(d.getTime());
    map[key] = { key, label: `${d.getMonth()+1}/${d.getDate()}`, count: 0, correct: 0 };
    arr.push(map[key]);
  }
  ensureHistoryArray().forEach(item => {
    const row = map[dayKey(item.ts)];
    if(!row) return;
    row.count += 1;
    if(item.correct === true) row.correct += 1;
  });
  return arr;
}

function streakDays(){
  const keys = new Set(ensureHistoryArray().map(item => dayKey(item.ts)));
  let streak = 0;
  const cursor = new Date();
  while(keys.has(dayKey(cursor.getTime()))){
    streak += 1;
    cursor.setDate(cursor.getDate() - 1);
  }
  return streak;
}

function favoriteQuestions(){
  return ALL_QUESTIONS.filter(q => getRecord(q.id).favorite);
}

function recentHistory(limit = 15){
  return ensureHistoryArray().slice().sort((a,b) => b.ts - a.ts).slice(0, limit).map(item => ({ ...item, q: QUESTION_LOOKUP[item.qid] || null }));
}

function questionSearchText(q){
  return [
    q.stem || "",
    q.prompt || "",
    q.source || "",
    q.subtype || "",
    q.passage || "",
    q.analysis || "",
    (q.traps || []).join(" "),
    Array.isArray(q.referenceAnswer) ? q.referenceAnswer.join(" ") : (q.referenceAnswer || "")
  ].join(" ").toLowerCase();
}

function practiceSummary(list){
  const answered = list.filter(isAnswered).length;
  const wrong = list.filter(isWrongQuestion).length;
  const favorites = list.filter(q => getRecord(q.id).favorite).length;
  return {
    total: list.length,
    answered,
    wrong,
    favorites,
    unanswered: Math.max(0, list.length - answered)
  };
}

function recommendedQuestions(limit = 6){
  const weakKeys = weakestCategories().map(item => item.bankKey);
  const seen = new Set();
  const result = [];
  function push(q){
    if(!q || seen.has(q.id)) return;
    seen.add(q.id);
    result.push(q);
  }
  ALL_QUESTIONS.filter(isWrongQuestion)
    .sort((a,b) => (getRecord(b.id).updatedAt || 0) - (getRecord(a.id).updatedAt || 0))
    .forEach(push);
  weakKeys.forEach(key => {
    ALL_QUESTIONS.filter(q => q.bankKey === key && !isAnswered(q)).slice(0, 4).forEach(push);
  });
  favoriteQuestions().forEach(push);
  ALL_QUESTIONS.filter(q => !isAnswered(q)).forEach(push);
  return result.slice(0, limit);
}

function stemAnalyzer(q){
  const text = q.type === "objective" ? (q.stem || "") : (q.prompt || q.stem || "");
  let task = q.type === "objective" ? (/不正确|错误/.test(text) ? "判断错项" : "判断正项") : "分点作答";
  if(/翻译/.test(text)) task = "翻译";
  else if(/概括/.test(text)) task = "概括";
  else if(/赏析|鉴赏/.test(text)) task = "赏析";
  else if(/分析/.test(text)) task = "分析";
  else if(/理解/.test(text)) task = "理解";
  else if(/比较/.test(text)) task = "比较";
  const focusPool = ["作用","好处","效果","特点","思路","情感","形象","语言","结构","手法","原因","相似之处","观点","意图","论证","翻译","概括"];
  const focus = focusPool.filter(token => text.includes(token)).slice(0, 4);
  let object = q.subtype || q.bankTitle;
  const quote = text.match(/“([^”]{1,16})”/);
  if(quote) object = `关键词：${quote[1]}`;
  const format = q.type === "objective"
    ? "逐项回原文核对对象、范围、逻辑关系。"
    : "先概括，再分析，最后用题干里的名词把答案扣紧。";
  return { task, object, focus, format };
}

function renderStemAnalyzer(q){
  const info = stemAnalyzer(q);
  return `
    <div class="small-grid" style="margin-top:14px">
      <div class="block">
        <strong>题干任务</strong>
        <div class="subtitle" style="margin-top:8px">${escapeHtml(info.task)}</div>
      </div>
      <div class="block">
        <strong>作答对象</strong>
        <div class="subtitle" style="margin-top:8px">${escapeHtml(info.object)}</div>
      </div>
      <div class="block teal">
        <strong>聚焦词</strong>
        <div style="margin-top:8px">${info.focus.length ? info.focus.map(item => `<span class="tag">${escapeHtml(item)}</span>`).join("") : '<span class="small">未触发关键词，优先回到题干核心名词。</span>'}</div>
      </div>
      <div class="block purple">
        <strong>输出提醒</strong>
        <div class="subtitle" style="margin-top:8px">${escapeHtml(info.format)}</div>
      </div>
    </div>
  `;
}

function objectiveMisjudgeTip(q, rec){
  if(rec.correct !== false) return "";
  const base = (q.traps || []).slice(0, 3);
  if(base.length){
    return `这题最像真的误判点通常是：${base.join("、")}。对照题干，把对象、范围、因果关系再核一遍。`;
  }
  return "这题要回到原文逐项核对，不要只看选项表面像不像。";
}

function missingScoringItems(q, rec){
  return (q.scoring || []).filter((item, idx) => !(rec.checks || {})[idx]);
}

function writingCompletion(draft){
  const keys = ["title","thesis","point1","point2","point3","reflection","fullText"];
  const filled = keys.filter(key => String(draft[key] || "").trim()).length;
  return { filled, total: keys.length, ratio: keys.length ? filled / keys.length : 0 };
}

function writingTemplates(prompt){
  return {
    intro: `开头模板：材料表面谈的是“${prompt.title}”，更深层折射出的则是${prompt.pain.replace(/。$/,"")}这一现实处境。`,
    body: "论证段模板：先点出现象/困境，再解释其社会或个体成因，最后写明这一段的解决方向与目的。",
    conclusion: `结尾模板：归根结底，${prompt.thesis}。但也要避免把单一做法绝对化，仍应回到具体处境中重建人的主体性、秩序感与连接感。`
  };
}

function normalizePaperSections(preset){
  return (Array.isArray(preset.sections) ? preset.sections : []).map((section, idx) => {
    const items = Array.isArray(section.items) ? section.items : [];
    const normalizedItems = items.map(item => {
      const qid = typeof item === "string" ? item : item.qid;
      const q = QUESTION_LOOKUP[qid];
      const points = Number((item && item.points) || questionMaxScore(q) || 0);
      return { qid, q, points };
    }).filter(item => item.q);
    const key = section.key || (normalizedItems[0] ? normalizedItems[0].q.bankKey : `section-${idx}`);
    return {
      ...section,
      key,
      normalizedItems,
      questions: normalizedItems.map(item => item.q),
      totalPoints: normalizedItems.reduce((sum, item) => sum + item.points, 0)
    };
  });
}

function getPaperItemMeta(preset, qid){
  for(const section of normalizePaperSections(preset)){
    const hit = section.normalizedItems.find(item => item.qid === qid);
    if(hit) return hit;
  }
  return { qid, q: QUESTION_LOOKUP[qid], points: questionMaxScore(QUESTION_LOOKUP[qid]) };
}


function paperSectionQuestions(preset, key){
  const section = normalizePaperSections(preset).find(item => item.key === key || item.title === key);
  return section ? section.questions : [];
}

function paperWeightedScore(presetId, q){
  const preset = PAPER_LOOKUP[presetId];
  const item = getPaperItemMeta(preset, q.id);
  const max = Number(item.points || 0);
  const resp = getPaperResponse(presetId, q.id);
  if(q.type === "objective"){
    return resp.selected === q.answer ? max : 0;
  }
  const rawMax = questionMaxScore(q) || 1;
  const raw = subjectiveScoreFromChecks(q, resp.checks || {});
  return Math.round((raw / rawMax) * max);
}

function paperSectionProgress(presetId, section){
  let answered = 0;
  section.questions.forEach(q => {
    const resp = getPaperResponse(presetId, q.id);
    if(q.type === "objective" && resp.selected !== null && resp.selected !== undefined) answered += 1;
    if(q.type === "subjective" && ((resp.text || "").trim() || Object.keys(resp.checks || {}).length)) answered += 1;
  });
  return { answered, total: section.questions.length };
}

function jumpToPaperSection(key){
  const el = document.getElementById(`paper-section-${key}`);
  if(el) el.scrollIntoView({ behavior: "smooth", block: "start" });
}


function saveState(){
  localStorage.setItem(STATE_KEY, JSON.stringify(state));
}

function escapeHtml(value){
  return String(value ?? "")
    .replace(/&/g,"&amp;")
    .replace(/</g,"&lt;")
    .replace(/>/g,"&gt;")
    .replace(/"/g,"&quot;")
    .replace(/'/g,"&#39;");
}

function nl2br(value){
  return escapeHtml(value).replace(/\n/g,"<br>");
}

function showToast(text){
  const el = document.getElementById("toast");
  el.textContent = text;
  el.classList.add("show");
  clearTimeout(showToast._t);
  showToast._t = setTimeout(() => el.classList.remove("show"), 1800);
}

function formatPct(ratio){
  if(ratio === null || ratio === undefined || Number.isNaN(ratio)) return "—";
  return Math.round(ratio * 100) + "%";
}

function average(arr){
  if(!arr.length) return null;
  return arr.reduce((s, v) => s + v, 0) / arr.length;
}

function uid(){
  return Date.now().toString(36) + Math.random().toString(36).slice(2,8);
}

function questionMaxScore(q){
  if(q.type === "objective") return 1;
  return (q.scoring || []).reduce((sum, item) => sum + Number(item.points || 0), 0);
}


function ensureRecord(qid){
  if(!state.records[qid]){
    state.records[qid] = {
      qid,
      selected: null,
      text: "",
      shownAnswer: false,
      correct: null,
      score: null,
      checks: {},
      hintIndex: 0,
      diagnosis: [],
      note: "",
      ruleDraft: "",
      favorite: false,
      updatedAt: null
    };
  }
  if(!state.records[qid].checks || typeof state.records[qid].checks !== "object") state.records[qid].checks = {};
  if(!Array.isArray(state.records[qid].diagnosis)) state.records[qid].diagnosis = [];
  if(typeof state.records[qid].hintIndex !== "number") state.records[qid].hintIndex = 0;
  if(typeof state.records[qid].favorite !== "boolean") state.records[qid].favorite = false;
  if(typeof state.records[qid].note !== "string") state.records[qid].note = "";
  if(typeof state.records[qid].ruleDraft !== "string") state.records[qid].ruleDraft = "";
  return state.records[qid];
}

function saveRecordPatch(qid, patch){
  const rec = ensureRecord(qid);
  Object.assign(rec, patch, { updatedAt: Date.now() });
  saveState();
}

function getRecord(qid){
  return ensureRecord(qid);
}


function getWritingDraft(promptId){
  if(!state.writingDrafts[promptId]){
    state.writingDrafts[promptId] = {
      title: "",
      thesis: "",
      point1: "",
      point2: "",
      point3: "",
      reflection: "",
      fullText: "",
      score_a: 0,
      score_b: 0,
      score_c: 0,
      score_d: 0,
      score_e: 0
    };
  }
  if(typeof state.writingDrafts[promptId].fullText !== "string") state.writingDrafts[promptId].fullText = "";
  return state.writingDrafts[promptId];
}

function getPaperSession(presetId){
  const preset = PAPER_LOOKUP[presetId];
  if(!state.paperSessions[presetId]){
    state.paperSessions[presetId] = {
      remainSec: preset.minutes * 60,
      running: false,
      responses: {},
      writing: {
        title: "",
        outline: "",
        score: 0
      },
      result: null
    };
  }
  const session = state.paperSessions[presetId];
  if(typeof session.remainSec !== "number") session.remainSec = preset.minutes * 60;
  if(typeof session.running !== "boolean") session.running = false;
  if(!session.responses || typeof session.responses !== "object") session.responses = {};
  if(!session.writing || typeof session.writing !== "object") session.writing = { title:"", outline:"", score:0 };
  return session;
}

function getPaperResponse(presetId, qid){
  const session = getPaperSession(presetId);
  if(!session.responses[qid]){
    session.responses[qid] = {
      selected: null,
      text: "",
      shownAnswer: false,
      checks: {},
      diagnosis: []
    };
  }
  const resp = session.responses[qid];
  if(!resp.checks || typeof resp.checks !== "object") resp.checks = {};
  if(!Array.isArray(resp.diagnosis)) resp.diagnosis = [];
  return resp;
}

function scoreRatio(q, rec){
  if(!rec) return null;
  if(q.type === "objective"){
    if(rec.correct === true) return 1;
    if(rec.correct === false) return 0;
    return null;
  }
  if(typeof rec.score === "number"){
    const max = questionMaxScore(q) || 1;
    return Math.max(0, Math.min(1, rec.score / max));
  }
  return null;
}

function isAnswered(q){
  const rec = state.records[q.id];
  if(!rec) return false;
  if(q.type === "objective") return rec.correct === true || rec.correct === false;
  return (rec.text && rec.text.trim()) || typeof rec.score === "number";
}

function isWrongQuestion(q){
  const rec = state.records[q.id];
  if(!rec) return false;
  const ratio = scoreRatio(q, rec);
  return ratio !== null && ratio < 0.6;
}

function categoryStats(bankKey){
  const qs = ALL_QUESTIONS.filter(q => q.bankKey === bankKey);
  const ratios = qs.map(q => scoreRatio(q, state.records[q.id])).filter(v => v !== null);
  return {
    bankKey,
    label: CATEGORY_LABELS[bankKey] || bankKey,
    total: qs.length,
    answered: ratios.length,
    ratio: average(ratios)
  };
}

function overallStats(){
  const stats = ["basic","language","modern1","modern2","classical","poetry"].map(categoryStats);
  const ratios = stats.map(s => s.ratio).filter(v => v !== null);
  const answered = ALL_QUESTIONS.filter(isAnswered).length;
  const wrong = ALL_QUESTIONS.filter(isWrongQuestion).length;
  return {
    total: ALL_QUESTIONS.length,
    real: ALL_QUESTIONS.filter(q => q.sourceType === "real").length,
    template: ALL_QUESTIONS.filter(q => q.sourceType === "template").length,
    answered,
    wrong,
    ratio: average(ratios),
    stats
  };
}

function diagnosisCounts(){
  const counts = {};
  Object.values(state.records).forEach(rec => {
    (rec.diagnosis || []).forEach(tag => {
      counts[tag] = (counts[tag] || 0) + 1;
    });
  });
  ALL_QUESTIONS.filter(isWrongQuestion).forEach(q => {
    (q.traps || []).forEach(tag => {
      counts[tag] = (counts[tag] || 0) + 1;
    });
  });
  return Object.entries(counts).sort((a,b) => b[1] - a[1]).map(([tag,count]) => ({ tag, count }));
}

function recentRecords(limit = 6){
  return Object.values(state.records)
    .filter(rec => rec.updatedAt)
    .sort((a,b) => b.updatedAt - a.updatedAt)
    .slice(0, limit)
    .map(rec => ({ ...rec, q: QUESTION_LOOKUP[rec.qid] }));
}

function weakestCategories(){
  return overallStats().stats
    .map(item => ({ ...item, orderRatio: item.ratio === null ? 999 : item.ratio }))
    .sort((a,b) => a.orderRatio - b.orderRatio)
    .slice(0,3);
}

function suggestedPlan(){
  const weak = weakestCategories().filter(item => item.ratio !== null);
  const diag = diagnosisCounts().slice(0,3);
  const steps = [];
  if(weak[0]) steps.push(`先补弱项：把「${weak[0].label}」至少做满 4 题，并强制写出“答案格式壳”。`);
  if(diag[0]) steps.push(`高频误区先清：最近最常见的问题是「${diag[0].tag}」，下一轮练习优先盯这一条。`);
  if(weak[1]) steps.push(`第二阶段刷「${weak[1].label}」，练“先概括、再分析、再贴题干”的顺序。`);
  steps.push(`最后做一套整卷，把客观题速度和主观题分点表达连起来。`);
  return steps;
}

function formatDateTime(ts){
  if(!ts) return "—";
  const d = new Date(ts);
  return `${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,"0")}-${String(d.getDate()).padStart(2,"0")} ${String(d.getHours()).padStart(2,"0")}:${String(d.getMinutes()).padStart(2,"0")}`;
}

function formatTimer(sec){
  const s = Math.max(0, sec|0);
  const mm = String(Math.floor(s/60)).padStart(2,"0");
  const ss = String(s%60).padStart(2,"0");
  return `${mm}:${ss}`;
}


function refreshPaperTimer(){
  const el = document.getElementById("paperTimer");
  if(!el) return;
  const session = getPaperSession(state.paperPreset);
  el.textContent = formatTimer(session.remainSec);
}


