function renderStatsCards(){
  const stats = overallStats();
  const diag = diagnosisCounts();
  const cards = [
    {label:"题库总量", value: stats.total, note:`真题 ${stats.real} / 模板 ${stats.template}`},
    {label:"已作答", value: stats.answered, note:`覆盖率 ${formatPct(stats.answered / stats.total)}`},
    {label:"整体得分率", value: formatPct(stats.ratio), note:"客观自动判分 + 主观自评分"},
    {label:"连续训练", value: `${streakDays()} 天`, note:`近 7 天记录 ${dailyTrend().reduce((s,x)=>s+x.count,0)} 次`},
    {label:"收藏题", value: favoriteQuestions().length, note: diag[0] ? `高频误区：${diag[0].tag}` : "可手动收藏重点题"}
  ];
  return `
    <section class="stats">
      ${cards.map(card => `
        <div class="stat-card">
          <div class="small">${escapeHtml(card.label)}</div>
          <div class="stat-value">${escapeHtml(card.value)}</div>
          <div class="small">${escapeHtml(card.note)}</div>
        </div>
      `).join("")}
    </section>
  `;
}


