function nextPracticeQuestion(mode){
  const list = filteredPracticeQuestions();
  if(!list.length) return;
  const currentIndex = list.findIndex(q => q.id === state.practiceQuestionId);
  if(mode === "random"){
    const next = list[Math.floor(Math.random() * list.length)];
    state.practiceQuestionId = next.id;
  }else{
    const nextIndex = currentIndex < 0 ? 0 : (currentIndex + 1) % list.length;
    state.practiceQuestionId = list[nextIndex].id;
  }
  saveState();
  renderApp();
  window.scrollTo({top:0, behavior:'smooth'});
}

function selectObjectiveOption(qid, idx){
  saveRecordPatch(qid, { selected: idx });
  renderApp();
}


function submitObjectiveQuestion(qid){
  const q = QUESTION_LOOKUP[qid];
  const rec = getRecord(qid);
  if(rec.selected === null || rec.selected === undefined){
    showToast("先选一个选项。");
    return;
  }
  const correct = rec.selected === q.answer;
  saveRecordPatch(qid, {
    shownAnswer: true,
    correct
  });
  pushHistory({ mode:"practice", qid, correct, score: correct ? 1 : 0 });
  renderApp();
}

function revealHint(qid){
  const q = QUESTION_LOOKUP[qid];
  const rec = getRecord(qid);
  const total = (q.hints || []).length;
  if(!total){
    showToast("这题没有额外提示。");
    return;
  }
  const nextIndex = Math.min(total, (rec.hintIndex || 0) + 1);
  saveRecordPatch(qid, { hintIndex: nextIndex });
  renderApp();
}


