function calculatePaperResult(presetId){
  const preset = PAPER_LOOKUP[presetId];
  const session = getPaperSession(presetId);
  const sections = normalizePaperSections(preset);
  const sectionResults = [];
  let objectiveScore = 0;
  let objectiveMax = 0;
  let subjectiveScore = 0;
  let subjectiveMax = 0;

  sections.forEach(section => {
    let score = 0;
    let max = 0;
    section.normalizedItems.forEach(item => {
      const q = item.q;
      const resp = getPaperResponse(presetId, q.id);
      const itemMax = Number(item.points || 0);
      max += itemMax;
      if(q.type === "objective"){
        objectiveMax += itemMax;
        if(resp.selected === q.answer){
          score += itemMax;
          objectiveScore += itemMax;
        }
      }else{
        const itemScore = paperWeightedScore(presetId, q);
        score += itemScore;
        subjectiveScore += itemScore;
        subjectiveMax += itemMax;
      }
    });
    sectionResults.push({ key: section.key, label: section.title, score, max });
  });

  const writingScore = Math.max(0, Math.min(60, Number(session.writing.score || 0)));
  const writingMax = 60;
  sectionResults.push({ key: "writing", label: "写作", score: writingScore, max: writingMax });

  const total = objectiveScore + subjectiveScore + writingScore;
  const totalMax = objectiveMax + subjectiveMax + writingMax;

  return {
    total,
    totalMax,
    objectiveScore,
    objectiveMax,
    subjectiveAndWritingScore: subjectiveScore + writingScore,
    subjectiveAndWritingMax: subjectiveMax + writingMax,
    sections: sectionResults
  };
}


function submitPaper(presetId){
  const preset = PAPER_LOOKUP[presetId];
  const session = getPaperSession(presetId);
  const result = calculatePaperResult(presetId);
  session.result = result;
  const sections = normalizePaperSections(preset);
  sections.forEach(section => {
    section.questions.forEach(q => {
      const resp = getPaperResponse(presetId, q.id);
      if(q.type === "objective"){
        if(resp.selected !== null && resp.selected !== undefined){
          saveRecordPatch(q.id, {
            selected: resp.selected,
            shownAnswer: !!resp.shownAnswer,
            correct: resp.selected === q.answer,
            diagnosis: Array.from(new Set([...(getRecord(q.id).diagnosis||[]), ...(resp.diagnosis||[])]))
          });
        }
      }else{
        saveRecordPatch(q.id, {
          text: resp.text || getRecord(q.id).text || "",
          shownAnswer: !!resp.shownAnswer,
          score: subjectiveScoreFromChecks(q, resp.checks),
          checks: resp.checks || {},
          diagnosis: Array.from(new Set([...(getRecord(q.id).diagnosis||[]), ...(resp.diagnosis||[])]))
        });
      }
    });
  });
  const prompt = WRITING_LOOKUP[preset.writingId];
  const draft = getWritingDraft(prompt.id);
  draft.title = session.writing.title || draft.title;
  draft.thesis = draft.thesis || prompt.thesis;
  if(session.writing.outline){
    draft.fullText = session.writing.outline;
  }
  if(session.writing.outline && !draft.point1 && !draft.point2 && !draft.point3){
    draft.point1 = prompt.bullets[0] || "";
    draft.point2 = prompt.bullets[1] || "";
    draft.point3 = prompt.bullets[2] || "";
    draft.reflection = prompt.bullets[3] || "";
  }
  pushHistory({ mode:"paper", qid:null, title:preset.title, correct:null, score:result.total, note:`整卷提交：${result.total}/${result.totalMax}` });
  saveState();
  renderApp();
  showToast("整卷结果已同步到诊断库");
}

function startPaperTimer(presetId){
  state.paperPreset = presetId;
  const session = getPaperSession(presetId);
  if(session.running) return;
  session.running = true;
  saveState();
  if(timerHandle) clearInterval(timerHandle);
  timerHandle = setInterval(() => {
    const activeSession = getPaperSession(state.paperPreset);
    if(!activeSession.running) return;
    activeSession.remainSec = Math.max(0, activeSession.remainSec - 1);
    if(activeSession.remainSec === 0){
      activeSession.running = false;
      saveState();
      refreshPaperTimer();
      showToast("计时结束");
      stopPaperTimer();
      renderApp();
      return;
    }
    saveState();
    refreshPaperTimer();
  }, 1000);
  renderApp();
}

function stopPaperTimer(){
  if(timerHandle){
    clearInterval(timerHandle);
    timerHandle = null;
  }
}

function pausePaperTimer(presetId){
  const session = getPaperSession(presetId);
  session.running = false;
  saveState();
  stopPaperTimer();
  if(state.activeView === "paper") renderApp();
}

function resetPaperTimer(presetId){
  const preset = PAPER_LOOKUP[presetId];
  const session = getPaperSession(presetId);
  session.running = false;
  session.remainSec = preset.minutes * 60;
  saveState();
  stopPaperTimer();
  renderApp();
}


