  draft.reflection = "结尾回扣：材料中的做法目的不是表面解决，而是重建人的主体性、秩序感与连接感。";
  draft.fullText = [templates.intro, `中心论点：${prompt.thesis}`, `分论点一：${draft.point1}`, `分论点二：${draft.point2}`, `分论点三：${draft.point3}`, templates.conclusion].join("\n\n");
