function copyWritingDraft(promptId){
  const draft = getWritingDraft(promptId);
  const text = (draft.fullText || "").trim() || [
    `标题：${draft.title || ''}`,
    `中心论点：${draft.thesis || ''}`,
    `分论点一：${draft.point1 || ''}`,
    `分论点二：${draft.point2 || ''}`,
    `分论点三：${draft.point3 || ''}`,
    `结尾回扣：${draft.reflection || ''}`
  ].join("\n");
  safeClipboardCopy(text).then(() => showToast("全文已复制"));
}
function addGlobalRule(){
  const input = document.getElementById("ruleInput");
  const text = (input.value || "").trim();
  if(!text){
    showToast("先输入规则。");
    return;
  }
  state.rules.push({ id: uid(), text, createdAt: Date.now() });
  saveState();
  renderApp();
  showToast("已加入规则库");
}

function deleteRule(id){
  state.rules = state.rules.filter(item => item.id !== id);
  saveState();
  renderApp();
}

function addGlobalNote(){
  const input = document.getElementById("noteInput");
  const text = (input.value || "").trim();
  if(!text){
    showToast("先输入笔记。");
    return;
  }
  state.notes.push({ id: uid(), text, createdAt: Date.now() });
  saveState();
  renderApp();
  showToast("已加入全局笔记");
}


function deleteNote(id){
  state.notes = state.notes.filter(item => item.id !== id);
  saveState();
  renderApp();
}

function exportReviewMarkdown(){
  const lines = [
    "# Review Pack",
    "",
    "## Rules",
    ...(state.rules.length ? state.rules.map(item => `- ${item.text}`) : ["- （暂无）"]),
    "",
    "## Notes",
    ...(state.notes.length ? state.notes.map(item => `- ${item.text}`) : ["- （暂无）"])
  ];
  const blob = new Blob([lines.join("\n")], {type: "text/markdown;charset=utf-8"});
  const url = URL.createObjectURL(blob);
  const a = document.createElement("a");
  a.href = url;
  a.download = "Review_Pack.md";
  document.body.appendChild(a);
  a.click();
  a.remove();
  URL.revokeObjectURL(url);
  showToast("已导出规则和笔记");
}


function exportStateData(){
  const payload = {
    exportedAt: new Date().toISOString(),
    version: 2,
    state
  };
  const blob = new Blob([JSON.stringify(payload, null, 2)], {type: "application/json"});
  const url = URL.createObjectURL(blob);
  const a = document.createElement("a");
  a.href = url;
  a.download = "Enhanced_NCEE_Chinese_Self_Test_Data.json";
  document.body.appendChild(a);
  a.click();
  a.remove();
  URL.revokeObjectURL(url);
  showToast("已导出数据");
}

function triggerImport(){
  document.getElementById("importFile").click();
}

function importStateFile(event){
  const file = event.target.files && event.target.files[0];
  if(!file) return;
  const reader = new FileReader();
  reader.onload = () => {
    try{
      const parsed = JSON.parse(reader.result);
      state = hydrateState(parsed.state || parsed);
      saveState();
      renderApp();
      showToast("导入成功");
    }catch(err){
      alert("导入失败：JSON 格式不正确。");
    }finally{
      event.target.value = "";
    }
  };
  reader.readAsText(file, "utf-8");
}

function resetAllData(){
  if(!confirm("确定要清空全部本地数据吗？此操作不可恢复。")) return;
  stopPaperTimer();
  localStorage.removeItem(STATE_KEY);
  state = defaultState();
  saveState();
  renderApp();
  showToast("已清空");
}



function switchView(view){
  if(!VIEW_LABELS[view]) return;
  state.activeView = view;
  saveState();
  renderApp();
  window.scrollTo({top:0, behavior:'smooth'});
}

function setKnowledgeMain(value){
  if(!DATA.knowledge[value]) return;
  state.knowledgeMain = value;
  saveState();
  renderApp();
}

function setKnowledgeQuery(value){
  state.knowledgeQuery = value;
  saveState();
  renderApp();
}

