function refreshWritingLive(promptId){
  const draft = getWritingDraft(promptId);
  const info = writingCompletion(draft);
  const ratioEl = document.getElementById('writingCompletionValue');
  if(ratioEl) ratioEl.textContent = `${info.filled}/${info.total}`;
  const barEl = document.getElementById('writingCompletionBar');
  if(barEl) barEl.style.width = `${Math.max(4, Math.round(info.ratio * 100))}%`;
  const textEl = document.getElementById('writingLiveText');
  if(textEl) textEl.textContent = draft.fullText || '在左侧输入全文，这里会实时显示。';
  const outlineEl = document.getElementById('writingOutlinePreview');
  if(outlineEl) outlineEl.innerHTML = [
    `<li><strong>标题：</strong>${escapeHtml(draft.title || '—')}</li>`,
    `<li><strong>中心论点：</strong>${escapeHtml(draft.thesis || '—')}</li>`,
    `<li><strong>分论点一：</strong>${escapeHtml(draft.point1 || '—')}</li>`,
    `<li><strong>分论点二：</strong>${escapeHtml(draft.point2 || '—')}</li>`,
    `<li><strong>分论点三：</strong>${escapeHtml(draft.point3 || '—')}</li>`,
    `<li><strong>结尾回扣：</strong>${escapeHtml(draft.reflection || '—')}</li>`
  ].join('');
  const countEl = document.getElementById('writingCharCount');
  if(countEl) countEl.textContent = `${countChars(draft.fullText || '')} 字`;
  const scoreEl = document.getElementById('writingScoreTotal');
  if(scoreEl){
    const total = ['score_a','score_b','score_c','score_d','score_e'].reduce((s,k)=>s+(Number(draft[k]||0)||0),0);
    scoreEl.textContent = String(total);
  }
}

function renderPaperObjective(q, presetId){
  const resp = getPaperResponse(presetId, q.id);
  return `
    <div style="margin-top:14px">
      <div class="q-stem">${nl2br(q.stem)}</div>
      ${(q.options || []).map((opt, idx) => {
        const active = resp.selected === idx;
        const isCorrect = resp.shownAnswer && idx === q.answer;
        const isWrong = resp.shownAnswer && active && idx !== q.answer;
        return `<button class="option ${active ? 'active' : ''} ${isCorrect ? 'correct' : ''} ${isWrong ? 'wrong' : ''}" onclick="selectPaperOption('${presetId}','${q.id}',${idx})"><span class="opt-code">${String.fromCharCode(65+idx)}</span><span>${escapeHtml(opt)}</span></button>`;
      }).join('')}
      <div class="toolbar">
        <button class="btn secondary" onclick="togglePaperAnswer('${presetId}','${q.id}')">${resp.shownAnswer ? '隐藏答案' : '查看答案'}</button>
      </div>
      ${resp.shownAnswer ? `
        <div class="analysis-stack">
          <div class="block good"><strong>正确答案</strong><div>${String.fromCharCode(65 + q.answer)}</div></div>
          <div class="block"><strong>解析</strong><div class="preview-box">${nl2br(q.analysis || '')}</div></div>
          ${(q.methodPath || []).length ? `<div class="block teal"><strong>方法路径</strong><ul class="list">${q.methodPath.map(x=>`<li>${escapeHtml(x)}</li>`).join('')}</ul></div>` : ''}
        </div>` : ''}
      <div class="chip-row">${(q.traps || []).map(tag => `<button class="diag-chip ${(resp.diagnosis || []).includes(tag) ? 'active' : ''}" onclick="togglePaperDiagnosis('${presetId}','${q.id}','${escapeHtml(tag)}')">${escapeHtml(tag)}</button>`).join('')}</div>
    </div>
  `;
}

function renderPaperSubjective(q, presetId){
  const resp = getPaperResponse(presetId, q.id);
  return `
    <div style="margin-top:14px">
      <div class="q-stem">${nl2br(q.stem)}</div>
      ${q.prompt ? `<div class="hint-line">${escapeHtml(q.prompt)}</div>` : ''}
      <textarea class="textarea" placeholder="先按题干要求独立作答，再决定是否展开参考答案。" oninput="updatePaperText('${presetId}','${q.id}',this.value)">${escapeHtml(resp.text || '')}</textarea>
      <div class="toolbar">
        <button class="btn secondary" onclick="fillPaperShell('${presetId}','${q.id}')">插入答案壳</button>
        <button class="btn secondary" onclick="togglePaperAnswer('${presetId}','${q.id}')">${resp.shownAnswer ? '隐藏答案' : '查看参考答案'}</button>
      </div>
      ${resp.shownAnswer ? `
        <div class="analysis-stack">
          ${renderScoringChecklist(q, { checks: resp.checks || {} }, 'paper')}
          <div class="block"><strong>参考答案</strong><div class="preview-box">${nl2br(Array.isArray(q.referenceAnswer) ? q.referenceAnswer.join('\n') : (q.referenceAnswer || ''))}</div></div>
          ${(q.methodPath || []).length ? `<div class="block teal"><strong>方法路径</strong><ul class="list">${q.methodPath.map(x=>`<li>${escapeHtml(x)}</li>`).join('')}</ul></div>` : ''}
        </div>` : ''}
      <div class="chip-row">${(q.traps || []).map(tag => `<button class="diag-chip ${(resp.diagnosis || []).includes(tag) ? 'active' : ''}" onclick="togglePaperDiagnosis('${presetId}','${q.id}','${escapeHtml(tag)}')">${escapeHtml(tag)}</button>`).join('')}</div>
    </div>
  `;
}

function renderPaper(){
  const preset = PAPER_LOOKUP[state.paperPreset] || DATA.paperPresets[0];
  const session = getPaperSession(preset.id);
  const sections = normalizePaperSections(preset);
  const result = session.result || calculatePaperResult(preset.id);
  return `
    ${renderHero('整卷模式：按高考节奏把阅读、诗文、语用、写作连成一场', '这里不是只看单题，而是把时间管理、分区推进、折算得分和写作收束一起练。提交后会把整卷结果同步回诊断库。', [`当前卷：${preset.title}`, `时长 ${preset.minutes} 分钟`, `分区 ${sections.length + 1} 个`, `写作题 ${WRITING_LOOKUP[preset.writingId].title}`])}
    <section class="card">
      <div class="toolbar">${DATA.paperPresets.map(item => `<button class="pill ${preset.id === item.id ? 'active' : ''}" onclick="setPaperPreset('${item.id}')">${escapeHtml(item.title)}</button>`).join('')}</div>
      <div class="space-between" style="margin-top:16px">
        <div>
          <h3>${escapeHtml(preset.title)}</h3>
          <div class="subtitle">${escapeHtml(preset.description || '')}</div>
        </div>
        <div class="row">
          <span class="source-tag">剩余时间 <strong id="paperTimer">${formatTimer(session.remainSec)}</strong></span>
          <button class="btn" onclick="startPaperTimer('${preset.id}')">开始计时</button>
          <button class="btn secondary" onclick="pausePaperTimer('${preset.id}')">暂停</button>
          <button class="btn secondary" onclick="resetPaperTimer('${preset.id}')">重置</button>
          <button class="btn warn" onclick="submitPaper('${preset.id}')">提交整卷</button>
        </div>
      </div>
      <div class="toolbar" style="margin-top:14px">${sections.map(sec => { const p = paperSectionProgress(preset.id, sec); return `<button class="pill small" onclick="jumpToPaperSection('${sec.key}')">${escapeHtml(sec.title)} ${p.answered}/${p.total}</button>`; }).join('')}<button class="pill small" onclick="jumpToPaperSection('writing')">写作</button></div>
    </section>
    <section class="grid-2">
      <div class="card">
        <h3>当前折算得分</h3>
        <div class="subtitle">客观题自动判，主观题按勾选点折算，写作分数可手动录入。</div>
        <div class="metric"><span>总分</span><div class="bar"><span style="width:${Math.max(4, Math.round((result.total/result.totalMax)*100))}%"></span></div><strong>${result.total}/${result.totalMax}</strong></div>
        <div class="metric"><span>客观</span><div class="bar"><span style="width:${Math.max(4, Math.round((result.objectiveScore/Math.max(1,result.objectiveMax))*100))}%"></span></div><strong>${result.objectiveScore}/${result.objectiveMax}</strong></div>
        <div class="metric"><span>主观+写作</span><div class="bar"><span style="width:${Math.max(4, Math.round((result.subjectiveAndWritingScore/Math.max(1,result.subjectiveAndWritingMax))*100))}%"></span></div><strong>${result.subjectiveAndWritingScore}/${result.subjectiveAndWritingMax}</strong></div>
      </div>
      <div class="card">
        <h3>分区完成情况</h3>
        <table class="table"><thead><tr><th>分区</th><th>得分</th><th>进度</th></tr></thead><tbody>${sections.map(sec => { const p = paperSectionProgress(preset.id, sec); const score = result.sections.find(x=>x.key===sec.key) || {score:0,max:sec.totalPoints}; return `<tr><td>${escapeHtml(sec.title)}</td><td>${score.score}/${score.max}</td><td>${p.answered}/${p.total}</td></tr>`; }).join('')}<tr><td>写作</td><td>${session.writing.score || 0}/60</td><td>${session.writing.outline ? '已写' : '未写'}</td></tr></tbody></table>
      </div>
    </section>
    ${sections.map(sec => `
      <section class="card section-anchor" id="paper-section-${sec.key}">
        <div class="space-between"><div><h3>${escapeHtml(sec.title)}</h3><div class="subtitle">本区共 ${sec.totalPoints} 分。</div></div><span class="count-badge">${paperSectionProgress(preset.id, sec).answered}/${sec.questions.length}</span></div>
        ${sec.normalizedItems.map(item => `
          <div class="paper-question">
            <div class="row">${renderSourceTags(item.q)} <span class="source-tag">本题 ${item.points} 分</span></div>
            ${renderPassageBlock(item.q)}
            ${renderStemAnalyzer(item.q)}
            ${item.q.type === 'objective' ? renderPaperObjective(item.q, preset.id) : renderPaperSubjective(item.q, preset.id)}
          </div>`).join('')}
      </section>`).join('')}
    <section class="card section-anchor" id="paper-section-writing">
      <div class="space-between"><div><h3>写作</h3><div class="subtitle">${escapeHtml(WRITING_LOOKUP[preset.writingId].title)}</div></div><span class="count-badge">60 分</span></div>
      <div class="block" style="margin-top:14px"><strong>材料</strong><div class="preview-box" style="margin-top:10px">${nl2br(WRITING_LOOKUP[preset.writingId].material)}</div></div>
      <div class="grid-2" style="margin-top:14px">
        <div class="block teal"><strong>中心论点</strong><div class="preview-box" style="margin-top:8px">${nl2br(WRITING_LOOKUP[preset.writingId].thesis)}</div></div>
        <div class="block purple"><strong>检查清单</strong><ul class="list">${WRITING_LOOKUP[preset.writingId].checklist.map(x=>`<li>${escapeHtml(x)}</li>`).join('')}</ul></div>
      </div>
      <div class="toolbar" style="margin-top:14px"><button class="btn secondary" onclick="loadPaperWritingOutline('${preset.id}')">载入提纲模板</button></div>
      <div class="grid-main" style="margin-top:14px">
        <div>
          <input class="input" placeholder="标题" value="${escapeHtml(session.writing.title || '')}" oninput="updatePaperWritingField('${preset.id}','title',this.value)">
          <textarea class="textarea" style="margin-top:12px" placeholder="在这里写提纲或全文。" oninput="updatePaperWritingField('${preset.id}','outline',this.value)">${escapeHtml(session.writing.outline || '')}</textarea>
        </div>
        <div class="block">
          <strong>写作计分</strong>
          <div class="subtitle" style="margin-top:8px">可手动录入估分或老师面批分数。</div>
          <input class="input" type="number" min="0" max="60" value="${escapeHtml(session.writing.score || 0)}" oninput="updatePaperWritingField('${preset.id}','score',this.value)">
          <div class="small" style="margin-top:10px">本卷提交时会把此分数计入总分。</div>
        </div>
      </div>
    </section>
  `;
}

function renderWriting(){
  const prompt = WRITING_LOOKUP[state.writingId] || DATA.writingPrompts[0];
  const draft = getWritingDraft(prompt.id);
  const info = writingCompletion(draft);
  const scoreTotal = ['score_a','score_b','score_c','score_d','score_e'].reduce((s,k)=>s+(Number(draft[k]||0)||0),0);
  const templates = writingTemplates(prompt);
  return `
    ${renderHero('写作强化：把困境、因果、做法、目的写成可迁移的骨架', '这一页不是单纯给范文，而是把审题、立意、分论点组织、全文扩写和自评完整连在一起。', [`当前题：${prompt.title}`, `完成度 ${info.filled}/${info.total}`, `可复制提纲/全文`, `支持模板插入`])}
    <section class="card">
      <div class="toolbar">${DATA.writingPrompts.map(item => `<button class="pill ${item.id === prompt.id ? 'active' : ''}" onclick="setWritingPrompt('${item.id}')">${escapeHtml(item.source)}</button>`).join('')}</div>
      <div class="block" style="margin-top:14px"><strong>${escapeHtml(prompt.title)}</strong><div class="preview-box" style="margin-top:10px">${nl2br(prompt.material)}</div></div>
      <div class="grid-3" style="margin-top:14px">
        <div class="block teal"><strong>现实困境</strong><div class="preview-box" style="margin-top:8px">${nl2br(prompt.pain)}</div></div>
        <div class="block"><strong>成因链</strong><ul class="list">${prompt.causeChain.map(x=>`<li>${escapeHtml(x)}</li>`).join('')}</ul></div>
        <div class="block purple"><strong>中心论点</strong><div class="preview-box" style="margin-top:8px">${nl2br(prompt.thesis)}</div></div>
      </div>
    </section>
    <section class="grid-main">
      <div class="card">
        <div class="space-between"><div><h3>写作工作台</h3><div class="subtitle">左边直接写，右边实时看提纲和完成度。</div></div><div class="row"><button class="btn" onclick="loadRecommendedWriting('${prompt.id}')">一键载入推荐骨架</button><button class="btn secondary" onclick="copyWritingOutline('${prompt.id}')">复制提纲</button><button class="btn secondary" onclick="copyWritingDraft('${prompt.id}')">复制全文</button></div></div>
        <div class="toolbar" style="margin-top:14px"><button class="pill small" onclick="insertWritingTemplate('${prompt.id}','intro')">插入开头模板</button><button class="pill small" onclick="insertWritingTemplate('${prompt.id}','body')">插入论证段模板</button><button class="pill small" onclick="insertWritingTemplate('${prompt.id}','conclusion')">插入结尾模板</button></div>
        <div class="grid-2" style="margin-top:14px">
          <input class="input" placeholder="标题" value="${escapeHtml(draft.title || '')}" oninput="updateWritingField('${prompt.id}','title',this.value)">
          <input class="input" placeholder="中心论点" value="${escapeHtml(draft.thesis || '')}" oninput="updateWritingField('${prompt.id}','thesis',this.value)">
          <textarea class="textarea compact" placeholder="分论点一" oninput="updateWritingField('${prompt.id}','point1',this.value)">${escapeHtml(draft.point1 || '')}</textarea>
          <textarea class="textarea compact" placeholder="分论点二" oninput="updateWritingField('${prompt.id}','point2',this.value)">${escapeHtml(draft.point2 || '')}</textarea>
          <textarea class="textarea compact" placeholder="分论点三" oninput="updateWritingField('${prompt.id}','point3',this.value)">${escapeHtml(draft.point3 || '')}</textarea>
          <textarea class="textarea compact" placeholder="结尾回扣 / 反思" oninput="updateWritingField('${prompt.id}','reflection',this.value)">${escapeHtml(draft.reflection || '')}</textarea>
        </div>
        <textarea class="textarea" style="margin-top:14px" placeholder="在这里写完整草稿。" oninput="updateWritingField('${prompt.id}','fullText',this.value)">${escapeHtml(draft.fullText || '')}</textarea>
        <div class="grid-3" style="margin-top:14px">
          ${['score_a','score_b','score_c','score_d','score_e'].map((k,idx)=>`<label class="block"><strong>维度 ${idx+1}</strong><input class="input" type="number" min="0" max="20" value="${escapeHtml(draft[k] || 0)}" oninput="updateWritingField('${prompt.id}','${k}',this.value)"></label>`).join('')}
        </div>
      </div>
      <div class="card sticky-card">
        <h3>实时提纲 / 完成度</h3>
        <div class="metric" style="margin-top:12px"><span>完成度</span><div class="bar"><span id="writingCompletionBar" style="width:${Math.max(4, Math.round(info.ratio*100))}%"></span></div><strong id="writingCompletionValue">${info.filled}/${info.total}</strong></div>
        <div class="block" style="margin-top:14px"><strong>推荐标题</strong><ul class="list">${prompt.titleOptions.map(x=>`<li>${escapeHtml(x)}</li>`).join('')}</ul></div>
        <div class="block teal" style="margin-top:14px"><strong>提纲预览</strong><ul class="list" id="writingOutlinePreview"><li><strong>标题：</strong>${escapeHtml(draft.title || '—')}</li><li><strong>中心论点：</strong>${escapeHtml(draft.thesis || '—')}</li><li><strong>分论点一：</strong>${escapeHtml(draft.point1 || '—')}</li><li><strong>分论点二：</strong>${escapeHtml(draft.point2 || '—')}</li><li><strong>分论点三：</strong>${escapeHtml(draft.point3 || '—')}</li><li><strong>结尾回扣：</strong>${escapeHtml(draft.reflection || '—')}</li></ul></div>
        <div class="block purple" style="margin-top:14px"><strong>模板提示</strong><ul class="list"><li>${escapeHtml(templates.intro)}</li><li>${escapeHtml(templates.body)}</li><li>${escapeHtml(templates.conclusion)}</li></ul></div>
        <div class="block warn" style="margin-top:14px"><strong>全文预览</strong><div class="small" id="writingCharCount" style="margin-top:8px">${countChars(draft.fullText || '')} 字</div><div class="preview-box" id="writingLiveText" style="margin-top:10px">${nl2br(draft.fullText || '在左侧输入全文，这里会实时显示。')}</div></div>
        <div class="block" style="margin-top:14px"><strong>自评总分</strong><div class="big-score" id="writingScoreTotal" style="margin-top:10px">${scoreTotal}</div></div>
      </div>
    </section>
  `;
}

function renderReview(){
  const tags = diagnosisCounts();
  const favs = favoriteQuestions();
  const wrongs = ALL_QUESTIONS.filter(isWrongQuestion);
  const history = recentHistory(20);
  const category = state.reviewCategory || 'all';
  const tag = (state.reviewTag || '').trim();
  let queue = ALL_QUESTIONS.filter(q => {
    if(category !== 'all' && q.bankKey !== category) return false;
    if(tag){
      const rec = getRecord(q.id);
      const text = `${(rec.diagnosis||[]).join(' ')} ${(q.traps||[]).join(' ')}`;
      if(!text.includes(tag)) return false;
    }
    const rec = getRecord(q.id);
    return rec.favorite || isWrongQuestion(q) || (rec.note || '').trim() || (rec.ruleDraft || '').trim();
  });
  queue = queue.slice().sort((a,b) => (getRecord(b.id).updatedAt || 0) - (getRecord(a.id).updatedAt || 0));
  return `
    ${renderHero('复盘中心：把错题、收藏、标签、规则卡和笔记沉淀成自己的体系', '这里不是“看过就算”，而是把错因标签、规则卡、重点题和最近动作全部串起来，形成下一轮训练的起点。', [`收藏 ${favs.length} 题`, `待补 ${wrongs.length} 题`, `规则 ${state.rules.length} 条`, `笔记 ${state.notes.length} 条`])}
    <section class="card">
      <div class="toolbar">${['all','basic','language','modern1','modern2','classical','poetry'].map(key => `<button class="pill ${category===key?'active':''}" onclick="setReviewCategory('${key}')">${escapeHtml(CATEGORY_LABELS[key] || '全部')}</button>`).join('')}</div>
      <div class="toolbar" style="margin-top:14px"><button class="pill ${tag===''?'active':''}" onclick="setReviewTag('')">全部标签</button>${tags.slice(0,10).map(item=>`<button class="pill small ${tag===item.tag?'active':''}" onclick="setReviewTag('${escapeHtml(item.tag)}')">${escapeHtml(item.tag)} · ${item.count}</button>`).join('')}</div>
    </section>
    <section class="grid-2">
      <div class="card">
        <h3>重点复盘队列</h3>
        <div class="subtitle">收藏、错题、有沉淀的题会一起汇进来。</div>
        ${queue.length ? `<ul class="list" style="margin-top:12px">${queue.map(q => { const rec = getRecord(q.id); return `<li><strong>${escapeHtml(CATEGORY_LABELS[q.bankKey])}</strong> · ${escapeHtml(q.source)}<br><span class="small">${rec.favorite ? '收藏题 · ' : ''}${isWrongQuestion(q) ? '待补题 · ' : ''}${escapeHtml((rec.diagnosis||[]).join(' / ') || (q.traps||[]).join(' / ') || '暂无标签')}</span><div class="toolbar" style="margin-top:10px"><button class="btn secondary" onclick="openPracticeQuestion('${q.id}')">打开此题</button>${rec.ruleDraft ? `<button class="btn secondary" onclick="safeClipboardCopy(${JSON.stringify(rec.ruleDraft)})">复制规则草稿</button>` : ''}</div></li>`; }).join('')}</ul>` : `<div class="small" style="margin-top:12px">当前筛选下还没有需要复盘的题。</div>`}
      </div>
      <div class="card">
        <h3>最近操作</h3>
        <div class="subtitle">最近 20 条记录，回看自己的训练轨迹。</div>
        ${history.length ? `<ul class="list" style="margin-top:12px">${history.map(item => `<li><strong>${escapeHtml(item.mode === 'paper' ? (item.title || '整卷') : (QUESTION_LOOKUP[item.qid] ? QUESTION_LOOKUP[item.qid].source : '记录'))}</strong><br><span class="small">${escapeHtml(item.note || '')} · ${formatDateTime(item.ts)}</span></li>`).join('')}</ul>` : `<div class="small" style="margin-top:12px">暂无历史。</div>`}
      </div>
    </section>
    <section class="grid-2">
      <div class="card">
        <h3>规则库</h3>
        <div class="subtitle">把可迁移的动作写成短句，下轮练题先看这里。</div>
        <div class="toolbar" style="margin-top:12px"><input id="ruleInput" class="input" placeholder="例如：现代文先问答后选择；古诗先定题材再抓意象。"><button class="btn" onclick="addGlobalRule()">加入规则</button><button class="btn secondary" onclick="exportReviewMarkdown()">导出规则/笔记</button></div>
        ${state.rules.length ? `<ul class="list" style="margin-top:12px">${state.rules.slice().reverse().map(item => `<li>${escapeHtml(item.text)}<div class="small">${formatDateTime(item.createdAt)}</div><div style="margin-top:8px"><button class="btn secondary" onclick="deleteRule('${item.id}')">删除</button></div></li>`).join('')}</ul>` : `<div class="small" style="margin-top:12px">还没有规则。</div>`}
      </div>
      <div class="card">
        <h3>全局笔记</h3>
        <div class="subtitle">适合记老师提醒、错因总结、阶段感受。</div>
        <div class="toolbar" style="margin-top:12px"><input id="noteInput" class="input" placeholder="写一条阶段笔记。"><button class="btn" onclick="addGlobalNote()">加入笔记</button></div>
        ${state.notes.length ? `<ul class="list" style="margin-top:12px">${state.notes.slice().reverse().map(item => `<li>${escapeHtml(item.text)}<div class="small">${formatDateTime(item.createdAt)}</div><div style="margin-top:8px"><button class="btn secondary" onclick="deleteNote('${item.id}')">删除</button></div></li>`).join('')}</ul>` : `<div class="small" style="margin-top:12px">还没有笔记。</div>`}
      </div>
    </section>
  `;
}

function renderApp(){
  renderSidebar();
  const app = document.getElementById('app');
  const view = state.activeView || 'dashboard';
  let html = '';
  if(view === 'knowledge') html = renderKnowledge();
  else if(view === 'practice') html = renderPractice();
  else if(view === 'paper') html = renderPaper();
  else if(view === 'writing') html = renderWriting();
  else if(view === 'review') html = renderReview();
  else html = renderDashboard();
  app.innerHTML = html;
  document.body.classList.toggle('focus-mode', !!state.focusMode);
  if(view === 'paper') refreshPaperTimer();
  if(view === 'writing') refreshWritingLive(state.writingId);
}

